/* ---------- .ase file generation (Adobe Swatch Exchange) ---------- */

function hexToRgbFloats(hex) {
  return [
    parseInt(hex.slice(1, 3), 16) / 255,
    parseInt(hex.slice(3, 5), 16) / 255,
    parseInt(hex.slice(5, 7), 16) / 255,
  ];
}

function buildAse(colors) {
  const entries = colors.map((c) => {
    const nameStr = c.name + "\u0000";
    const nameLen = nameStr.length;
    const blockLen = 2 + nameLen * 2 + 4 + 12 + 2;
    return { nameStr, nameLen, blockLen, hex: c.hex };
  });

  const totalBytes =
    12 + entries.reduce((sum, e) => sum + 2 + 4 + e.blockLen, 0);
  const buf = new ArrayBuffer(totalBytes);
  const dv = new DataView(buf);
  let o = 0;

  "ASEF".split("").forEach((ch) => dv.setUint8(o++, ch.charCodeAt(0)));
  dv.setUint16(o, 1); o += 2;
  dv.setUint16(o, 0); o += 2;
  dv.setUint32(o, entries.length); o += 4;

  entries.forEach((e) => {
    dv.setUint16(o, 0x0001); o += 2;
    dv.setUint32(o, e.blockLen); o += 4;
    dv.setUint16(o, e.nameLen); o += 2;
    for (let i = 0; i < e.nameLen; i++) {
      dv.setUint16(o, e.nameStr.charCodeAt(i)); o += 2;
    }
    "RGB ".split("").forEach((ch) => dv.setUint8(o++, ch.charCodeAt(0)));
    hexToRgbFloats(e.hex).forEach((f) => {
      dv.setFloat32(o, f); o += 4;
    });
    dv.setUint16(o, 0x0002); o += 2;
  });

  return buf;
}

function downloadAse(filename, colors) {
  const blob = new Blob([buildAse(colors)], {
    type: "application/octet-stream",
  });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  a.remove();
  URL.revokeObjectURL(url);
}

/* ---------- value helpers ---------- */

function toGray(hex) {
  const [r, g, b] = hexToRgbFloats(hex);
  const y = Math.round((0.2126 * r + 0.7152 * g + 0.0722 * b) * 255);
  const h = y.toString(16).padStart(2, "0");
  return `#${h}${h}${h}`;
}

function isLight(hex) {
  const [r, g, b] = hexToRgbFloats(hex);
  return 0.2126 * r + 0.7152 * g + 0.0722 * b > 0.6;
}

/* ---------- components ---------- */

function Swatch({ color, grayscale, onCopy, copied }) {
  const shown = grayscale ? toGray(color.hex) : color.hex;
  const lightBg = isLight(shown);
  return (
    <button
      onClick={() => onCopy(color.hex)}
      title={`Copy ${color.hex}`}
      style={{
        background: shown,
        border: `1px solid ${INK}`,
        borderRadius: 2,
        cursor: "pointer",
        height: 84,
        display: "flex",
        flexDirection: "column",
        justifyContent: "flex-end",
        alignItems: "flex-start",
        padding: 8,
        transition: "transform 120ms ease",
      }}
      onMouseEnter={(e) => (e.currentTarget.style.transform = "translateY(-3px)")}
      onMouseLeave={(e) => (e.currentTarget.style.transform = "translateY(0)")}
    >
      <span
        style={{
          fontFamily: "'IBM Plex Mono', monospace",
          fontSize: 10,
          lineHeight: 1.3,
          textAlign: "left",
          color: lightBg ? INK : PAPER,
        }}
      >
        {color.name}
        <br />
        {copied === color.hex ? "copied ✓" : color.hex.toUpperCase()}
      </span>
    </button>
  );
}

